const r = $input.first().json.report || {};
const t = r.totals || {};
const byPurpose = r.by_purpose || {};
const recent = r.recent || [];
const card = (label, value, color) => '<div style="background:'+(color||'#f9fafb')+';padding:12px;border-radius:6px;flex:1;min-width:130px"><div style="font-size:10px;color:#6b7280;text-transform:uppercase">'+label+'</div><div style="font-size:22px;font-weight:bold;color:#1f2937;margin-top:4px">'+(value!=null?value:'-')+'</div></div>';
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:6px 8px;border-bottom:1px solid #eee;font-size:12px">'+c+'</td>').join('')+'</tr>';
const stateOf = tk => {
  if (tk.revoked_at) return '<span style="background:#6b7280;color:white;padding:1px 6px;border-radius:3px;font-size:10px">REVOKED</span>';
  if (tk.expires_at && new Date(tk.expires_at) < new Date()) return '<span style="background:#ea580c;color:white;padding:1px 6px;border-radius:3px;font-size:10px">EXPIRED</span>';
  if (!tk.last_used_at) return '<span style="background:#3b82f6;color:white;padding:1px 6px;border-radius:3px;font-size:10px">UNUSED</span>';
  return '<span style="background:#10b981;color:white;padding:1px 6px;border-radius:3px;font-size:10px">ACTIVE</span>';
};
const recentRows = recent.length>0 ? recent.map(tk=>row([
  stateOf(tk),
  '<code>'+tk.purpose+'</code>',
  tk.project_name||'-',
  tk.client_name||'-',
  tk.expires_at ? new Date(tk.expires_at).toISOString().slice(0,10) : '-',
  tk.last_used_at ? new Date(tk.last_used_at).toISOString().slice(0,16).replace('T',' ') : '<i style="color:#9ca3af">nunca</i>',
  new Date(tk.created_at).toISOString().slice(0,10)
])).join('') : row(['<i>Sin tokens</i>','','','','','','']);
const purposeChips = Object.entries(byPurpose).map(([k,v])=>'<span style="background:#e0e7ff;color:#3730a3;padding:3px 10px;border-radius:12px;font-size:12px;margin:2px;display:inline-block">'+k+': <b>'+v+'</b></span>').join('') || '<i style="color:#6b7280">sin tokens activos</i>';
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ArquitAI Tokens</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}h2{color:#374151;font-size:15px;margin:20px 0 8px}.cards{display:flex;gap:10px;flex-wrap:wrap;margin:12px 0}table{width:100%;background:white;border-collapse:collapse}thead{background:#1f2937;color:white}thead th{padding:8px;text-align:left;font-size:11px}.meta{color:#64748b;font-size:13px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Tokens de cliente</h1>' +
'<div class="meta">' + new Date().toLocaleString('es-ES') + ' — ATENCION: vista solo lectura. Para crear/revocar usa client_token_create / client_token_revoke.</div>' +
'<div class="cards">' +
  card('Activos', t.active||0, '#f0fdf4') +
  card('Revocados', t.revoked||0) +
  card('Expirados', t.expired||0, (t.expired||0)>0?'#fef3c7':null) +
  card('Nunca usados', t.never_used||0) +
  card('Expiran 7d', t.expiring_7d||0, (t.expiring_7d||0)>0?'#fef3c7':null) +
'</div>' +
'<h2>Activos por purpose</h2>' +
'<div style="background:white;padding:12px;border-radius:6px">'+purposeChips+'</div>' +
'<h2>Tokens recientes (top 30)</h2>' +
'<table><thead><tr><th>Estado</th><th>Purpose</th><th>Proyecto</th><th>Cliente</th><th>Expira</th><th>Ultimo uso</th><th>Creado</th></tr></thead><tbody>'+recentRows+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">Vista read-only. Datos de la tabla client_access_tokens.</p>' +
'</body></html>';
return [{ json: { html } }];
